@implements IAsyncDisposable
@inject IJSRuntime JS

<div @ref="_dropZoneRef" class="drop-zone @(_isDragOver ? "drag-over" : "")">
    <p>Drag &amp; drop files here</p>
</div>

@if (_files.Count > 0)
{
    <ul class="file-list">
        @foreach (var file in _files)
        {
            <li class="file-entry @(file.Error is not null ? "file-error" : "")">
                <div class="file-info">
                    @if (file.Error is not null)
                    {
                        <span class="error-message">@file.Error</span>
                        <span class="file-name">@file.Info.Name</span>
                    }
                    else
                    {
                        <span class="file-name">@file.Info.Name</span>
                        <span class="file-size">@FormatSize(file.Info.Size)</span>
                        <span class="file-type">@file.Info.Type</span>
                    }
                </div>
                <button class="btn-remove" @onclick="() => RemoveFile(file)">Remove</button>
            </li>
        }
    </ul>
}

@code {
    private const long MaxFileSize = 10 * 1024 * 1024; // 10 MB

    [Parameter]
    public EventCallback<List<FileInfo>> OnFilesChanged { get; set; }

    private ElementReference _dropZoneRef;
    private IJSObjectReference? _module;
    private IJSObjectReference? _dropZoneInstance;
    private bool _isDragOver;
    private readonly List<FileEntry> _files = new();

    private DotNetObjectReference<FileDropZone>? _dotNetRef;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _dotNetRef = DotNetObjectReference.Create(this);
            _module = await JS.InvokeAsync<IJSObjectReference>("import",
                "./_content/sv-87d4779114754206837e6158ab55f43c/Components/FileDropZone.razor.js");
            _dropZoneInstance = await _module.InvokeAsync<IJSObjectReference>(
                "initDropZone", _dropZoneRef, _dotNetRef);
        }
    }

    [JSInvokable]
    public void OnDragOverChanged(bool isDragOver)
    {
        _isDragOver = isDragOver;
        StateHasChanged();
    }

    [JSInvokable]
    public async Task OnFilesDropped(FileMetadata[] droppedFiles)
    {
        _isDragOver = false;

        foreach (var meta in droppedFiles)
        {
            var info = new FileInfo(meta.Name, meta.Size, meta.Type);
            string? error = meta.Size > MaxFileSize
                ? $"File exceeds the 10 MB limit ({FormatSize(meta.Size)})"
                : null;
            _files.Add(new FileEntry(info, error));
        }

        await NotifyParent();
        StateHasChanged();
    }

    private async Task RemoveFile(FileEntry entry)
    {
        _files.Remove(entry);
        await NotifyParent();
    }

    private async Task NotifyParent()
    {
        var accepted = _files
            .Where(f => f.Error is null)
            .Select(f => f.Info)
            .ToList();
        await OnFilesChanged.InvokeAsync(accepted);
    }

    private static string FormatSize(long bytes) => bytes switch
    {
        < 1024 => $"{bytes} B",
        < 1024 * 1024 => $"{bytes / 1024.0:F1} KB",
        _ => $"{bytes / (1024.0 * 1024.0):F1} MB"
    };

    public async ValueTask DisposeAsync()
    {
        if (_dropZoneInstance is not null)
        {
            await _dropZoneInstance.InvokeVoidAsync("dispose");
            await _dropZoneInstance.DisposeAsync();
        }
        if (_module is not null)
            await _module.DisposeAsync();
        _dotNetRef?.Dispose();
    }

    public record FileMetadata(string Name, long Size, string Type);
    private record FileEntry(FileInfo Info, string? Error);
}

.drop-zone {
    border: 2px dashed #6c757d;
    border-radius: 8px;
    padding: 40px;
    text-align: center;
    color: #6c757d;
    transition: border-color 0.2s, background-color 0.2s;
    cursor: default;
}

.drop-zone.drag-over {
    border-color: #0d6efd;
    background-color: rgba(13, 110, 253, 0.08);
    color: #0d6efd;
}

.file-list {
    list-style: none;
    padding: 0;
    margin-top: 12px;
}

.file-entry {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 8px 12px;
    border: 1px solid #dee2e6;
    border-radius: 4px;
    margin-bottom: 6px;
}

.file-entry.file-error {
    border-color: #dc3545;
    background-color: rgba(220, 53, 69, 0.06);
}

.file-info {
    display: flex;
    gap: 12px;
    align-items: center;
    flex-wrap: wrap;
}

.file-name {
    font-weight: 600;
}

.file-size,
.file-type {
    color: #6c757d;
    font-size: 0.9em;
}

.error-message {
    color: #dc3545;
    font-weight: 600;
}

.btn-remove {
    background: none;
    border: 1px solid #dc3545;
    color: #dc3545;
    border-radius: 4px;
    padding: 2px 10px;
    cursor: pointer;
    font-size: 0.85em;
}

.btn-remove:hover {
    background-color: #dc3545;
    color: #fff;
}

export function initDropZone(element, dotNetRef) {
    let dragCounter = 0;

    function onDragEnter(e) {
        e.preventDefault();
        dragCounter++;
        if (dragCounter === 1) {
            dotNetRef.invokeMethodAsync('OnDragOverChanged', true);
        }
    }

    function onDragOver(e) {
        e.preventDefault();
    }

    function onDragLeave(e) {
        e.preventDefault();
        dragCounter--;
        if (dragCounter === 0) {
            dotNetRef.invokeMethodAsync('OnDragOverChanged', false);
        }
    }

    function onDrop(e) {
        e.preventDefault();
        dragCounter = 0;

        const files = Array.from(e.dataTransfer.files).map(f => ({
            name: f.name,
            size: f.size,
            type: f.type || 'unknown'
        }));

        if (files.length > 0) {
            dotNetRef.invokeMethodAsync('OnFilesDropped', files);
        } else {
            dotNetRef.invokeMethodAsync('OnDragOverChanged', false);
        }
    }

    element.addEventListener('dragenter', onDragEnter);
    element.addEventListener('dragover', onDragOver);
    element.addEventListener('dragleave', onDragLeave);
    element.addEventListener('drop', onDrop);

    return {
        dispose: () => {
            element.removeEventListener('dragenter', onDragEnter);
            element.removeEventListener('dragover', onDragOver);
            element.removeEventListener('dragleave', onDragLeave);
            element.removeEventListener('drop', onDrop);
        }
    };
}

